golden_st:
STEP_RED    := RUN AND NEXT_PB AND NOT STEP_GREEN AND NOT STEP_YELLOW AND NOT STEP_RED OR NEXT_PB AND STEP_YELLOW AND NOT STEP_RED AND NOT STEP_GREEN;
STEP_GREEN  := NEXT_PB AND STEP_RED AND NOT STEP_GREEN AND NOT STEP_YELLOW;
STEP_YELLOW := NEXT_PB AND STEP_GREEN AND NOT STEP_RED AND NOT STEP_YELLOW;
LIGHT_RED    := STEP_RED AND NOT STEP_GREEN AND NOT STEP_YELLOW;
LIGHT_GREEN  := STEP_GREEN AND NOT STEP_RED AND NOT STEP_YELLOW;
LIGHT_YELLOW := STEP_YELLOW AND NOT STEP_RED AND NOT STEP_GREEN;
